using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var mlContext = new MLContext(seed: 42);

// --- Load data ---
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var data = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// --- Full pipeline: map "Yes"/"No" → bool Label, then train ---
var labelKeys = new[] { "Yes", "No" };
var labelValues = new[] { true, false };

var fullPipeline = mlContext.Transforms.Conversion.MapValue(
        "Label", new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false }, "Churned")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

// --- Train/test split ---
var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

Console.WriteLine("Training churn prediction model...");
var model = fullPipeline.Fit(split.TrainSet);

// --- Evaluate ---
var predictions = model.Transform(split.TestSet);
try
{
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
    Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
    Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");
}
catch (ArgumentOutOfRangeException)
{
    Console.WriteLine("Note: Test set too small for full metrics. Add more data for reliable evaluation.");
    var trainMetrics = mlContext.BinaryClassification.Evaluate(model.Transform(split.TrainSet));
    Console.WriteLine($"Train Accuracy: {trainMetrics.Accuracy:F4} (for reference only)");
}

// --- Save model ---
var finalModel = fullPipeline.Fit(data);
var modelPath = Path.Combine(AppContext.BaseDirectory, "ChurnModel.zip");
mlContext.Model.Save(finalModel, data.Schema, modelPath);
Console.WriteLine($"Model saved to {modelPath}");

// --- Predict on a sample customer ---
var predEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(finalModel);
var sample = new CustomerData { Age = 40, Income = 70000, Region = "West", PurchaseHistory = 2 };
var result = predEngine.Predict(sample);
Console.WriteLine($"\nSample prediction — Churned: {result.PredictedLabel}, Probability: {result.Probability:F4}");

// --- Web API for predictions ---
var builder = WebApplication.CreateBuilder(args);
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);
var app = builder.Build();

app.MapPost("/predict", (CustomerData customer,
    PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(customer);
    return Results.Ok(new { prediction.PredictedLabel, prediction.Probability });
});

app.Run();

// --- Data classes ---
public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}
